const express = require('express');
const crypto = require('crypto');
const app = express();

app.use(express.json());

const SECRET_KEY = process.env.SECRET_KEY || 'your-secret-key-change-in-production';
const HMAC_ALGORITHM = 'sha256';

const users = new Map();
const levelConfigs = new Map([
  [1, { minTime: 10, maxTime: 300, maxScore: 1000, baseReward: 100 }],
  [2, { minTime: 15, maxTime: 400, maxScore: 1500, baseReward: 150 }],
  [3, { minTime: 20, maxTime: 500, maxScore: 2000, baseReward: 200 }],
  [4, { minTime: 25, maxTime: 600, maxScore: 2500, baseReward: 250 }],
  [5, { minTime: 30, maxTime: 700, maxScore: 3000, baseReward: 300 }]
]);

const sessions = new Map();
const completionHistory = new Map();

function generateHMAC(data, secret) {
  return crypto.createHmac(HMAC_ALGORITHM, secret).update(data).digest('hex');
}

function verifyHMAC(data, signature, secret) {
  const expectedSignature = generateHMAC(data, secret);
  return crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expectedSignature));
}

function generateSessionToken() {
  return crypto.randomBytes(32).toString('hex');
}

function getUserSecret(userId) {
  if (!users.has(userId)) {
    const userSecret = crypto.randomBytes(32).toString('hex');
    users.set(userId, {
      id: userId,
      secret: userSecret,
      coins: 0,
      completedLevels: new Set(),
      lastActivity: Date.now()
    });
  }
  return users.get(userId).secret;
}

function detectAnomalies(userId, levelId, score, time) {
  const config = levelConfigs.get(levelId);
  if (!config) return { valid: false, reason: 'Invalid level' };

  if (time < config.minTime) {
    return { valid: false, reason: 'Completion time too fast' };
  }

  if (time > config.maxTime) {
    return { valid: false, reason: 'Completion time too slow' };
  }

  if (score > config.maxScore) {
    return { valid: false, reason: 'Score exceeds maximum' };
  }

  if (score < 0) {
    return { valid: false, reason: 'Invalid score' };
  }

  const history = completionHistory.get(userId) || [];
  const recentCompletions = history.filter(h => Date.now() - h.timestamp < 60000);
  
  if (recentCompletions.length > 10) {
    return { valid: false, reason: 'Too many completions in short time' };
  }

  const sameLevelRecent = recentCompletions.filter(h => h.levelId === levelId);
  if (sameLevelRecent.length > 3) {
    return { valid: false, reason: 'Same level completed too frequently' };
  }

  const avgTime = history.filter(h => h.levelId === levelId).reduce((sum, h) => sum + h.time, 0) / Math.max(1, history.filter(h => h.levelId === levelId).length);
  if (avgTime > 0 && time < avgTime * 0.3) {
    return { valid: false, reason: 'Suspicious improvement in completion time' };
  }

  return { valid: true };
}

function calculateReward(levelId, score, time) {
  const config = levelConfigs.get(levelId);
  if (!config) return 0;

  const scoreMultiplier = score / config.maxScore;
  const timeBonus = Math.max(0, (config.maxTime - time) / config.maxTime);
  
  const reward = Math.floor(config.baseReward * (0.5 + scoreMultiplier * 0.3 + timeBonus * 0.2));
  
  return Math.max(10, Math.min(reward, config.baseReward * 2));
}

app.post('/api/level/start', (req, res) => {
  const { userId, levelId } = req.body;

  if (!userId || !levelId) {
    return res.status(400).json({ error: 'Missing userId or levelId' });
  }

  if (!levelConfigs.has(levelId)) {
    return res.status(400).json({ error: 'Invalid level' });
  }

  const userSecret = getUserSecret(userId);
  const sessionToken = generateSessionToken();
  const timestamp = Date.now();
  
  const sessionData = {
    userId,
    levelId,
    startTime: timestamp,
    token: sessionToken
  };

  sessions.set(sessionToken, sessionData);

  const signatureData = `${userId}:${levelId}:${timestamp}:${sessionToken}`;
  const signature = generateHMAC(signatureData, userSecret);

  setTimeout(() => sessions.delete(sessionToken), 900000);

  res.json({
    sessionToken,
    timestamp,
    signature
  });
});

app.post('/api/level/complete', (req, res) => {
  const { userId, levelId, score, time, sessionToken, clientSignature } = req.body;

  if (!userId || !levelId || score === undefined || !time || !sessionToken || !clientSignature) {
    return res.status(400).json({ error: 'Missing required fields' });
  }

  const session = sessions.get(sessionToken);
  if (!session) {
    return res.status(401).json({ error: 'Invalid or expired session' });
  }

  if (session.userId !== userId || session.levelId !== levelId) {
    return res.status(401).json({ error: 'Session mismatch' });
  }

  const sessionAge = Date.now() - session.startTime;
  if (sessionAge < time * 1000 * 0.8) {
    return res.status(400).json({ error: 'Completion time inconsistent with session' });
  }

  const userSecret = getUserSecret(userId);
  const signatureData = `${userId}:${levelId}:${score}:${time}:${sessionToken}`;
  
  if (!verifyHMAC(signatureData, clientSignature, userSecret)) {
    return res.status(401).json({ error: 'Invalid signature' });
  }

  const anomalyCheck = detectAnomalies(userId, levelId, score, time);
  if (!anomalyCheck.valid) {
    return res.status(400).json({ error: 'Suspicious activity detected', reason: anomalyCheck.reason });
  }

  const reward = calculateReward(levelId, score, time);
  
  const user = users.get(userId);
  user.coins += reward;
  user.completedLevels.add(levelId);
  user.lastActivity = Date.now();

  const history = completionHistory.get(userId) || [];
  history.push({
    levelId,
    score,
    time,
    reward,
    timestamp: Date.now()
  });
  completionHistory.set(userId, history);

  sessions.delete(sessionToken);

  res.json({
    success: true,
    reward,
    totalCoins: user.coins,
    levelId,
    score,
    time
  });
});

app.post('/api/rewards/claim', (req, res) => {
  const { userId, rewardType, signature } = req.body;

  if (!userId || !rewardType || !signature) {
    return res.status(400).json({ error: 'Missing required fields' });
  }

  const userSecret = getUserSecret(userId);
  const signatureData = `${userId}:${rewardType}:claim`;
  
  if (!verifyHMAC(signatureData, signature, userSecret)) {
    return res.status(401).json({ error: 'Invalid signature' });
  }

  const user = users.get(userId);
  
  if (rewardType === 'daily') {
    const lastClaim = user.lastDailyClaim || 0;
    const hoursSinceLastClaim = (Date.now() - lastClaim) / (1000 * 60 * 60);
    
    if (hoursSinceLastClaim < 24) {
      return res.status(400).json({ error: 'Daily reward already claimed' });
    }
    
    const dailyReward = 50;
    user.coins += dailyReward;
    user.lastDailyClaim = Date.now();
    
    return res.json({
      success: true,
      reward: dailyReward,
      totalCoins: user.coins,
      nextClaimAvailable: Date.now() + (24 * 60 * 60 * 1000)
    });
  }

  res.status(400).json({ error: 'Invalid reward type' });
});

app.get('/api/user/:userId/stats', (req, res) => {
  const { userId } = req.params;
  
  const user = users.get(userId);
  if (!user) {
    return res.status(404).json({ error: 'User not found' });
  }

  const history = completionHistory.get(userId) || [];
  
  res.json({
    userId,
    coins: user.coins,
    completedLevels: Array.from(user.completedLevels),
    totalCompletions: history.length,
    lastActivity: user.lastActivity
  });
});

